/* Shared variables */
boolean flag[2] = {false, false};
int turn;

/* Process i (i = 0 or 1) */
do {
 // Entry section
 flag[i] = true;
 turn = 1 - i;
 while (flag[1 - i] && turn == 1 - i);

 // Critical section
 // ... access shared resources ...

 // Exit section
 flag[i] = false;

 // Remainder section
 // ... other work ...
} while (true);

/* Semaphore structure */
typedef struct {
 int value;
 queue waitingQueue;
} semaphore;

/* wait operation (P operation) */
wait(semaphore *S) {
 S->value--;
 if (S->value < 0) {
 // Block this process
 addToQueue(S->waitingQueue, currentProcess);
 block(currentProcess);
 }
}

/* signal operation (V operation) */
signal(semaphore *S) {
 S->value++;
 if (S->value <= 0) {
 // Wake up a waiting process
 process = removeFromQueue(S->waitingQueue);
 wakeup(process);
 }
}

/* Test-and-set instruction (atomic) */
boolean testAndSet(boolean *target) {
 boolean temp = *target;
 *target = true;
 return temp;
}

/* Lock implementation using test-and-set */
boolean lock = false;

/* Process trying to acquire lock */
do {
 // Entry - busy wait (spinlock)
 while (testAndSet(&lock));

 // Critical section
 // ... access shared resources ...

 // Exit
 lock = false;

 // Remainder section
 // ... other work ...
} while (true);

/* Shared variables */
semaphore empty = N; // N empty slots
semaphore full = 0; // 0 filled slots
semaphore mutex = 1; // Mutual exclusion

/* Producer process */
producer() {
 while (true) {
 item = produceItem();
 wait(empty); // Wait for empty slot
 wait(mutex); // Enter critical section
 addToBuffer(item);
 signal(mutex); // Exit critical section
 signal(full); // Signal filled slot
 }
}

/* Consumer process */
consumer() {
 while (true) {
 wait(full); // Wait for filled slot
 wait(mutex); // Enter critical section
 item = removeFromBuffer();
 signal(mutex); // Exit critical section
 signal(empty); // Signal empty slot
 consumeItem(item);
 }
}

/* Monitor definition */
monitor AccountMonitor {
 private int balance = 0;
 private condition canWithdraw;

 /* Procedure to deposit money */
 procedure deposit(amount) {
 balance = balance + amount;
 canWithdraw.signal(); // Wake waiting withdrawers
 }

 /* Procedure to withdraw money */
 procedure withdraw(amount) {
 while (balance < amount) {
 canWithdraw.wait(); // Wait until enough balance
 }
 balance = balance - amount;
 return amount;
 }

 /* Procedure to check balance */
 procedure getBalance() {
 return balance;
 }
}
